div.script:
(function () {
    'use strict';

    var srcEl   = document.getElementById('lx_src_text');
    var resEl   = document.getElementById('lx_result_text');
    var srcSel  = document.getElementById('lx_src_lang');
    var tgtSel  = document.getElementById('lx_tgt_lang');
    var btn     = document.getElementById('lx_translate_btn');
    var btnTxt  = document.getElementById('lx_btn_text');
    var spinner = document.getElementById('lx_btn_spinner');
    var errBnr  = document.getElementById('lx_error_banner');
    var vocabRow = document.getElementById('lx_add_vocab_row');
    var addBtn  = document.getElementById('lx_add_vocab_btn');
    var vocabLink = document.getElementById('lx_vocab_link');
    var copyBtn = document.getElementById('lx_copy_btn');
    var charCnt = document.getElementById('lx_char_count');
    var swapBtn = document.getElementById('lx_swap_langs');

    /* char counter */
    srcEl.addEventListener('input', function () {
        charCnt.textContent = srcEl.value.length + ' / 2000';
    });

    /* swap languages */
    swapBtn.addEventListener('click', function () {
        var s = srcSel.value, t = tgtSel.value;
        srcSel.value = t;
        tgtSel.value = s;
        /* also swap text content if result is filled */
        if (resEl.value.trim()) {
            var tmp = srcEl.value;
            srcEl.value = resEl.value;
            resEl.value = tmp;
            charCnt.textContent = srcEl.value.length + ' / 2000';
        }
    });

    /* copy button */
    if (copyBtn) {
        copyBtn.addEventListener('click', function () {
            navigator.clipboard.writeText(resEl.value).then(function () {
                copyBtn.title = 'Copied!';
                setTimeout(function () { copyBtn.title = 'Copy translation'; }, 1500);
            });
        });
    }

    /* Ctrl+Enter shortcut */
    srcEl.addEventListener('keydown', function (e) {
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            e.preventDefault();
            doTranslate();
        }
    });

    btn.addEventListener('click', doTranslate);

    function setLoading(on) {
        btn.disabled = on;
        btnTxt.style.display  = on ? 'none' : '';
        spinner.style.display = on ? '' : 'none';
    }

    function showError(msg) {
        errBnr.textContent = '⚠ ' + msg;
        errBnr.style.display = '';
    }
    function clearError() { errBnr.style.display = 'none'; errBnr.textContent = ''; }

    function doTranslate() {
        var text = srcEl.value.trim();
        if (!text) return;
        clearError();
        vocabRow.style.display = 'none';
        resEl.value = '';
        copyBtn.style.display = 'none';
        setLoading(true);

        var fd = new FormData();
        fd.append('text', text);
        fd.append('source_lang', srcSel.value);
        fd.append('target_lang', tgtSel.value);

        fetch('/translator/translate', {
            method: 'POST',
            body: fd,
        })
        .then(function (r) { return r.json(); })
        .then(function (data) {
            setLoading(false);
            if (data.status === 'ok' && data.result) {
                resEl.value = data.result;
                copyBtn.style.display = '';
                vocabRow.style.display = '';
                if (vocabLink) vocabLink.style.display = 'none';
            } else {
                showError(data.message || 'Translation failed. Try again.');
            }
        })
        .catch(function (err) {
            setLoading(false);
            showError('Network error: ' + err.message);
        });
    }

    /* Add to Vocabulary */
    if (addBtn) {
        addBtn.addEventListener('click', function () {
            var text = srcEl.value.trim();
            var trans = resEl.value.trim();
            if (!text || !trans) return;

            addBtn.disabled = true;
            addBtn.textContent = 'Saving…';

            var fd = new FormData();
            fd.append('text', text);
            fd.append('translation', trans);
            fd.append('source_lang', srcSel.value);
            fd.append('target_lang', tgtSel.value);
            /* CSRF token */
            var csrfMeta = document.querySelector('meta[name=csrf-token]');
            if (csrfMeta) fd.append('csrf_token', csrfMeta.getAttribute('content'));

            fetch('/translator/add', { method: 'POST', body: fd })
            .then(function (r) { return r.json(); })
            .then(function (data) {
                if (data.status === 'ok') {
                    addBtn.textContent = '✅ Saved!';
                    if (vocabLink) {
                        vocabLink.href = data.vocab_url || '/my/vocabulary';
                        vocabLink.style.display = '';
                    }
                } else {
                    addBtn.disabled = false;
                    addBtn.textContent = '⭐ Add to Vocabulary';
                    showError(data.message || 'Could not save entry.');
                }
            })
            .catch(function (err) {
                addBtn.disabled = false;
                addBtn.textContent = '⭐ Add to Vocabulary';
                showError('Network error: ' + err.message);
            });
        });
    }
}());
